import { useQuery, useMutation, useQueryClient } from '@tanstack/react-query'
import { toast } from 'sonner'
import { supabase } from '../../core/supabase/client'
import { logError } from '../../core/utils/logger'
import { buildQueryKey } from '../../core/hooks/useQueryBase'
import type { QueryOptions, PaginatedResult } from '../../core/types/api'
import type {
  Incidencia,
  IncidenciaInsert,
  IncidenciaUpdate,
  TipoIncidencia,
  EstadoIncidencia,
  PrioridadIncidencia,
} from '../../core/types/entities'

const RESOURCE = 'incidencias'

export interface IncidenciaConEmpresa extends Incidencia {
  empresa?: { id: string; nombre: string; nif: string | null } | null
  contrato?: { id: string; numero_contrato: string | null } | null
  asignado?: { id: string; full_name: string | null } | null
}

export interface IncidenciasKPI {
  abiertas: number
  criticas: number
  altas: number
  vencidas: number
}

export function useIncidenciasKPI() {
  return useQuery({
    queryKey: [RESOURCE, 'kpi'],
    queryFn: async (): Promise<IncidenciasKPI> => {
      const { data, error } = await supabase
        .from('v_incidencias_kpi')
        .select('*')
        .maybeSingle()
      if (error) { logError(error, 'useIncidenciasKPI'); throw error }
      return (data as IncidenciasKPI | null) ?? { abiertas: 0, criticas: 0, altas: 0, vencidas: 0 }
    },
  })
}

export function useIncidencias(options?: QueryOptions) {
  return useQuery({
    queryKey: buildQueryKey(RESOURCE, options),
    queryFn: async (): Promise<PaginatedResult<IncidenciaConEmpresa>> => {
      const page = options?.page ?? 1
      const pageSize = options?.pageSize ?? 20
      const from = (page - 1) * pageSize
      const to = from + pageSize - 1

      let q = supabase
        .from('incidencias')
        .select(
          '*, empresa:empresas!incidencias_empresa_id_fkey(id, nombre, nif), contrato:contratos!incidencias_contrato_id_fkey(id, numero_contrato), asignado:user_profiles!incidencias_asignado_a_fkey(id, full_name)',
          { count: 'exact' },
        )
        .is('deleted_at', null)

      const f = options?.filter ?? {}
      if (f.estado) q = q.eq('estado', f.estado as never)
      if (f.tipo) q = q.eq('tipo', f.tipo as never)
      if (f.prioridad) q = q.eq('prioridad', f.prioridad as never)
      if (f.empresa_id) q = q.eq('empresa_id', f.empresa_id as string)
      if (f.asignado_a) q = q.eq('asignado_a', f.asignado_a as string)

      const sortField = options?.sort?.field ?? 'fecha_apertura'
      const sortAsc = options?.sort?.direction === 'asc'
      q = q.order(sortField, { ascending: sortAsc }).range(from, to)

      const { data, count, error } = await q
      if (error) { logError(error, 'useIncidencias'); throw error }
      return { data: (data ?? []) as unknown as IncidenciaConEmpresa[], count: count ?? 0, page, pageSize }
    },
  })
}

export async function fetchIncidenciasForExport(filter?: {
  estado?: EstadoIncidencia
  tipo?: TipoIncidencia
  prioridad?: PrioridadIncidencia
  empresa_id?: string
}): Promise<IncidenciaConEmpresa[]> {
  let q = supabase
    .from('incidencias')
    .select(
      '*, empresa:empresas!incidencias_empresa_id_fkey(id, nombre, nif), contrato:contratos!incidencias_contrato_id_fkey(id, numero_contrato), asignado:user_profiles!incidencias_asignado_a_fkey(id, full_name)',
    )
    .is('deleted_at', null)

  if (filter?.estado) q = q.eq('estado', filter.estado as never)
  if (filter?.tipo) q = q.eq('tipo', filter.tipo as never)
  if (filter?.prioridad) q = q.eq('prioridad', filter.prioridad as never)
  if (filter?.empresa_id) q = q.eq('empresa_id', filter.empresa_id)

  const { data, error } = await q.order('fecha_apertura', { ascending: false }).limit(10000)
  if (error) { logError(error, 'fetchIncidenciasForExport'); throw error }
  return (data ?? []) as unknown as IncidenciaConEmpresa[]
}

export function useIncidenciaById(id: string | undefined) {
  return useQuery({
    queryKey: [RESOURCE, 'byId', id],
    enabled: Boolean(id),
    queryFn: async () => {
      const { data, error } = await supabase
        .from('incidencias')
        .select(
          '*, empresa:empresas!incidencias_empresa_id_fkey(id, nombre, nif), contrato:contratos!incidencias_contrato_id_fkey(id, numero_contrato), asignado:user_profiles!incidencias_asignado_a_fkey(id, full_name)',
        )
        .eq('id', id!)
        .is('deleted_at', null)
        .maybeSingle()
      if (error) { logError(error, 'useIncidenciaById'); throw error }
      return (data as IncidenciaConEmpresa | null) ?? null
    },
  })
}

export function useCreateIncidencia() {
  const qc = useQueryClient()
  return useMutation({
    mutationFn: async (input: IncidenciaInsert) => {
      const { data, error } = await supabase
        .from('incidencias')
        .insert(input as never)
        .select('*')
        .single()
      if (error) { logError(error, 'useCreateIncidencia'); throw error }
      return data as unknown as Incidencia
    },
    onSuccess: () => {
      qc.invalidateQueries({ queryKey: [RESOURCE] })
      toast.success('Incidencia creada')
    },
    onError: (e) => toast.error('No se pudo crear la incidencia', { description: (e as Error).message }),
  })
}

export function useUpdateIncidencia() {
  const qc = useQueryClient()
  return useMutation({
    mutationFn: async ({ id, patch }: { id: string; patch: IncidenciaUpdate }) => {
      const { data, error } = await supabase
        .from('incidencias')
        .update(patch as never)
        .eq('id', id)
        .select('*')
        .single()
      if (error) { logError(error, 'useUpdateIncidencia'); throw error }
      return data as unknown as Incidencia
    },
    onSuccess: (_d, vars) => {
      qc.invalidateQueries({ queryKey: [RESOURCE] })
      qc.invalidateQueries({ queryKey: [RESOURCE, 'byId', vars.id] })
      toast.success('Incidencia actualizada')
    },
    onError: (e) => toast.error('No se pudo actualizar la incidencia', { description: (e as Error).message }),
  })
}

export function useDeleteIncidencia() {
  const qc = useQueryClient()
  return useMutation({
    mutationFn: async (id: string) => {
      const { error } = await supabase
        .from('incidencias')
        .update({ deleted_at: new Date().toISOString() } as never)
        .eq('id', id)
      if (error) { logError(error, 'useDeleteIncidencia'); throw error }
    },
    onSuccess: () => {
      qc.invalidateQueries({ queryKey: [RESOURCE] })
      toast.success('Incidencia eliminada')
    },
    onError: (e) => toast.error('No se pudo eliminar la incidencia', { description: (e as Error).message }),
  })
}

-- FASE 22 — Módulo de Incidencias
-- Gestión de reclamaciones y problemas de clientes con contratos activos.

-- Types
DO $$ BEGIN
  CREATE TYPE public.tipo_incidencia AS ENUM (
    'facturacion', 'cambio_comercializadora', 'corte_suministro',
    'potencia', 'acceso_red', 'otro'
  );
EXCEPTION WHEN duplicate_object THEN NULL; END $$;

DO $$ BEGIN
  CREATE TYPE public.estado_incidencia AS ENUM (
    'abierta', 'en_gestion', 'pendiente_cliente',
    'pendiente_comercializadora', 'resuelta', 'cerrada'
  );
EXCEPTION WHEN duplicate_object THEN NULL; END $$;

DO $$ BEGIN
  CREATE TYPE public.prioridad_incidencia AS ENUM ('baja', 'media', 'alta', 'critica');
EXCEPTION WHEN duplicate_object THEN NULL; END $$;

-- Tabla
CREATE TABLE IF NOT EXISTS public.incidencias (
  id uuid PRIMARY KEY DEFAULT gen_random_uuid(),
  empresa_id uuid NOT NULL REFERENCES public.empresas(id) ON DELETE CASCADE,
  contrato_id uuid REFERENCES public.contratos(id) ON DELETE SET NULL,
  cups text,
  titulo text NOT NULL,
  descripcion text,
  tipo public.tipo_incidencia NOT NULL DEFAULT 'otro',
  estado public.estado_incidencia NOT NULL DEFAULT 'abierta',
  prioridad public.prioridad_incidencia NOT NULL DEFAULT 'media',
  asignado_a uuid REFERENCES public.user_profiles(id) ON DELETE SET NULL,
  fecha_apertura timestamptz NOT NULL DEFAULT now(),
  fecha_limite timestamptz,
  fecha_resolucion timestamptz,
  importe_reclamado numeric(12, 2),
  importe_recuperado numeric(12, 2),
  notas_resolucion text,
  created_by uuid REFERENCES public.user_profiles(id) ON DELETE SET NULL,
  created_at timestamptz NOT NULL DEFAULT now(),
  updated_at timestamptz NOT NULL DEFAULT now(),
  deleted_at timestamptz
);

-- Índices
CREATE INDEX IF NOT EXISTS idx_incidencias_empresa ON public.incidencias(empresa_id) WHERE deleted_at IS NULL;
CREATE INDEX IF NOT EXISTS idx_incidencias_contrato ON public.incidencias(contrato_id) WHERE deleted_at IS NULL;
CREATE INDEX IF NOT EXISTS idx_incidencias_asignado ON public.incidencias(asignado_a) WHERE deleted_at IS NULL;
CREATE INDEX IF NOT EXISTS idx_incidencias_estado ON public.incidencias(estado) WHERE deleted_at IS NULL;
CREATE INDEX IF NOT EXISTS idx_incidencias_prioridad ON public.incidencias(prioridad) WHERE deleted_at IS NULL;
CREATE INDEX IF NOT EXISTS idx_incidencias_fecha_apertura ON public.incidencias(fecha_apertura DESC);

-- Trigger updated_at
CREATE OR REPLACE FUNCTION public.tg_incidencias_touch()
RETURNS trigger LANGUAGE plpgsql AS $$
BEGIN
  NEW.updated_at := now();
  IF NEW.estado IN ('resuelta', 'cerrada') AND OLD.estado NOT IN ('resuelta', 'cerrada') THEN
    NEW.fecha_resolucion := now();
  END IF;
  RETURN NEW;
END $$;

DROP TRIGGER IF EXISTS tg_incidencias_touch ON public.incidencias;
CREATE TRIGGER tg_incidencias_touch
  BEFORE UPDATE ON public.incidencias
  FOR EACH ROW EXECUTE FUNCTION public.tg_incidencias_touch();

-- RLS
ALTER TABLE public.incidencias ENABLE ROW LEVEL SECURITY;

DROP POLICY IF EXISTS "incidencias_all_authenticated" ON public.incidencias;
CREATE POLICY "incidencias_all_authenticated" ON public.incidencias
  FOR ALL USING (auth.role() = 'authenticated') WITH CHECK (auth.role() = 'authenticated');

-- KPI agregado para Dashboard
CREATE OR REPLACE VIEW public.v_incidencias_kpi AS
SELECT
  COUNT(*) FILTER (WHERE estado NOT IN ('resuelta', 'cerrada'))::int AS abiertas,
  COUNT(*) FILTER (WHERE estado NOT IN ('resuelta', 'cerrada') AND prioridad = 'critica')::int AS criticas,
  COUNT(*) FILTER (WHERE estado NOT IN ('resuelta', 'cerrada') AND prioridad = 'alta')::int AS altas,
  COUNT(*) FILTER (WHERE fecha_limite IS NOT NULL AND fecha_limite < now() AND estado NOT IN ('resuelta', 'cerrada'))::int AS vencidas
FROM public.incidencias
WHERE deleted_at IS NULL;

COMMENT ON TABLE public.incidencias IS 'FASE 22 — Incidencias y reclamaciones de clientes.';

import { useEffect } from 'react'
import { supabase } from '../supabase/client'
import { useAuthStore } from '../stores/authStore'
import { logError } from '../utils/logger'
import type { Session } from '@supabase/supabase-js'
import type { UserProfile } from '../types/entities'

async function fetchProfile(userId: string): Promise<UserProfile | null> {
  try {
    const { data, error } = await supabase
      .from('user_profiles')
      .select('*')
      .eq('id', userId)
      .maybeSingle()

    if (error) {
      logError(error, 'useAuth.fetchProfile')
      return null
    }

    return (data as UserProfile | null) ?? null
  } catch (e) {
    logError(e, 'useAuth.fetchProfile')
    return null
  }
}

function bootstrapFromSession(session: Session): UserProfile {
  const email = session.user.email ?? ''
  const meta = (session.user.user_metadata ?? {}) as Record<string, unknown>

  const fullNameMeta =
    typeof meta.full_name === 'string'
      ? meta.full_name
      : typeof meta.nombre_completo === 'string'
      ? meta.nombre_completo
      : null

  return {
    id: session.user.id,
    email,
    full_name: fullNameMeta ?? email.split('@')[0] ?? 'Usuario',
    role: 'client',
    status: 'active',
    approved: false,
    avatar_url: null,
    created_at: new Date().toISOString(),
    updated_at: new Date().toISOString(),
  }
}

let initialized = false

function ensureAuthInitialized() {
  if (initialized) return
  initialized = true

  console.log('[useAuth] ensureAuthInitialized - suscribiendo onAuthStateChange')

  supabase.auth.onAuthStateChange((event, session) => {
    console.log('[useAuth] onAuthStateChange:', event, 'session:', !!session)

    const store = useAuthStore.getState()
    store.setSession(session)

    if (session?.user) {
      store.setUser(bootstrapFromSession(session))
    } else {
      store.setUser(null)
    }

    store.setLoading(false)

    if (session?.user) {
      fetchProfile(session.user.id)
        .then((profile) => {
          if (profile) useAuthStore.getState().setUser(profile)
        })
        .catch((err) => console.error('[useAuth] fetchProfile bg:', err))
    }
  })
}

export function useAuth() {
  const user = useAuthStore((s) => s.user)
  const session = useAuthStore((s) => s.session)
  const loading = useAuthStore((s) => s.loading)
  const logout = useAuthStore((s) => s.logout)

  useEffect(() => {
    ensureAuthInitialized()
  }, [])

  const signIn = async (email: string, password: string) => {
    const { error } = await supabase.auth.signInWithPassword({ email, password })
    if (error) {
      logError(error, 'useAuth.signIn')
      throw error
    }
  }

  const signOut = async () => {
    const { error } = await supabase.auth.signOut()
    if (error) logError(error, 'useAuth.signOut')
    logout()
  }

  return {
    user,
    session,
    loading,
    signIn,
    signOut,
    getCurrentUserProfile: () =>
      session?.user ? fetchProfile(session.user.id) : Promise.resolve(null),
  }
}

