    const applySession = async (s: Session | null) => {
      if (!mounted) return;
      setSession(s);
      setUser(s?.user ?? null);
      if (!s?.user) {
        setProfile(null);
        setLoading(false);
        return;
      }
      setLoading(false);
      const p = await ensureUserProfile(s.user.id, s.user.email ?? '');
      if (mounted && p) setProfile(p);
    };

    supabase.auth.getSession().then(({ data: { session: s } }) => {
