import { useQuery, useMutation, useQueryClient } from '@tanstack/react-query'
import { toast } from 'sonner'
import { supabase } from '../../core/supabase/client'
import { logError } from '../../core/utils/logger'
import type {
  Documento,
  DocumentoInsert,
  EntidadTipo,
} from '../../core/types/entities'

const RESOURCE = 'documentos'

export interface DocumentoConUsuario extends Documento {
  subido_por_profile?: { id: string; full_name: string | null } | null
}

export function useDocumentosPorEntidad(entidadTipo: EntidadTipo, entidadId: string | undefined) {
  return useQuery({
    queryKey: [RESOURCE, entidadTipo, entidadId],
    enabled: Boolean(entidadId),
    queryFn: async (): Promise<DocumentoConUsuario[]> => {
      const { data, error } = await supabase
        .from('documentos' as never)
        .select('*, subido_por_profile:user_profiles!documentos_subido_por_fkey(id, full_name)')
        .eq('entidad_tipo' as never, entidadTipo as never)
        .eq('entidad_id' as never, entidadId! as never)
        .is('deleted_at' as never, null)
        .order('created_at' as never, { ascending: false })
      if (error) { logError(error, 'useDocumentosPorEntidad'); throw error }
      return (data ?? []) as unknown as DocumentoConUsuario[]
    },
  })
}

export function useUploadDocumento() {
  const qc = useQueryClient()
  return useMutation({
    mutationFn: async ({
      file,
      entidadTipo,
      entidadId,
      descripcion,
    }: {
      file: File
      entidadTipo: EntidadTipo
      entidadId: string
      descripcion?: string
    }) => {
      const ext = file.name.split('.').pop() ?? 'bin'
      const path = `${entidadTipo}/${entidadId}/${crypto.randomUUID()}.${ext}`

      const { error: uploadError } = await supabase.storage
        .from('documentos')
        .upload(path, file, { contentType: file.type, upsert: false })
      if (uploadError) { logError(uploadError, 'uploadDocumento.storage'); throw uploadError }

      const userId = (await supabase.auth.getUser()).data.user?.id ?? null

      const insert: DocumentoInsert = {
        entidad_tipo: entidadTipo,
        entidad_id: entidadId,
        nombre: file.name,
        tipo: ext,
        ruta_storage: path,
        tamanio: file.size,
        mime_type: file.type || null,
        descripcion: descripcion || null,
        subido_por: userId,
      }

      const { data, error } = await supabase
        .from('documentos' as never)
        .insert(insert as never)
        .select('*')
        .single()
      if (error) { logError(error, 'uploadDocumento.insert'); throw error }
      return data as unknown as Documento
    },
    onSuccess: (_d, vars) => {
      qc.invalidateQueries({ queryKey: [RESOURCE, vars.entidadTipo, vars.entidadId] })
      toast.success('Documento subido')
    },
    onError: (e) => toast.error('Error al subir documento', { description: (e as Error).message }),
  })
}

export function useDeleteDocumento() {
  const qc = useQueryClient()
  return useMutation({
    mutationFn: async ({ id, rutaStorage }: { id: string; rutaStorage: string }) => {
      await supabase.storage.from('documentos').remove([rutaStorage])

      const { error } = await supabase
        .from('documentos' as never)
        .update({ deleted_at: new Date().toISOString() } as never)
        .eq('id', id)
      if (error) { logError(error, 'useDeleteDocumento'); throw error }
    },
    onSuccess: () => {
      qc.invalidateQueries({ queryKey: [RESOURCE] })
      toast.success('Documento eliminado')
    },
    onError: (e) => toast.error('No se pudo eliminar', { description: (e as Error).message }),
  })
}

export function getDocumentoUrl(rutaStorage: string): string {
  const { data } = supabase.storage.from('documentos').getPublicUrl(rutaStorage)
  return data.publicUrl
}

-- FASE 24 — Módulo de Documentos
-- Registro de archivos adjuntos vinculados a entidades del CRM.
-- Los archivos se almacenan en Supabase Storage (bucket 'documentos').

-- Tabla
CREATE TABLE IF NOT EXISTS public.documentos (
  id uuid PRIMARY KEY DEFAULT gen_random_uuid(),
  entidad_tipo text NOT NULL CHECK (entidad_tipo IN ('empresa', 'contacto', 'contrato', 'oportunidad')),
  entidad_id uuid NOT NULL,
  nombre text NOT NULL,
  tipo text,
  ruta_storage text NOT NULL,
  tamanio bigint,
  mime_type text,
  descripcion text,
  subido_por uuid REFERENCES public.user_profiles(id) ON DELETE SET NULL,
  created_at timestamptz NOT NULL DEFAULT now(),
  deleted_at timestamptz
);

-- Índices
CREATE INDEX IF NOT EXISTS idx_documentos_entidad ON public.documentos(entidad_tipo, entidad_id) WHERE deleted_at IS NULL;
CREATE INDEX IF NOT EXISTS idx_documentos_subido_por ON public.documentos(subido_por) WHERE deleted_at IS NULL;

-- RLS
ALTER TABLE public.documentos ENABLE ROW LEVEL SECURITY;

DROP POLICY IF EXISTS "documentos_all_authenticated" ON public.documentos;
CREATE POLICY "documentos_all_authenticated" ON public.documentos
  FOR ALL USING (auth.role() = 'authenticated') WITH CHECK (auth.role() = 'authenticated');

-- Supabase Storage bucket (idempotent — requires superuser or dashboard)
-- INSERT INTO storage.buckets (id, name, public, file_size_limit, allowed_mime_types)
-- VALUES ('documentos', 'documentos', false, 52428800, ARRAY['application/pdf','image/png','image/jpeg','application/vnd.openxmlformats-officedocument.spreadsheetml.sheet','application/vnd.openxmlformats-officedocument.wordprocessingml.document','text/csv'])
-- ON CONFLICT (id) DO NOTHING;

-- Storage policies (requires storage schema access)
-- CREATE POLICY "documentos_auth_select" ON storage.objects FOR SELECT TO authenticated USING (bucket_id = 'documentos');
-- CREATE POLICY "documentos_auth_insert" ON storage.objects FOR INSERT TO authenticated WITH CHECK (bucket_id = 'documentos');
-- CREATE POLICY "documentos_auth_delete" ON storage.objects FOR DELETE TO authenticated USING (bucket_id = 'documentos');

COMMENT ON TABLE public.documentos IS 'FASE 24 — Documentos adjuntos vinculados a entidades CRM.';

import { useState } from 'react'
import { useParams, Link } from 'react-router-dom'
import { ArrowLeft, Pencil, Plus, Trash2, X } from 'lucide-react'
import { useEmpresaById, useUpdateEmpresa, useDeleteEmpresa } from './api'
import EmpresaForm from './components/EmpresaForm'
import ActividadTimeline from '../actividades/components/ActividadTimeline'
import { useContactosPorEmpresa, useCreateContacto } from '../contactos/api'
import ContactoForm from '../contactos/components/ContactoForm'
import { formatDate } from '../../core/utils/dates'
import ConfirmDialog from '../../components/ui/ConfirmDialog'
import type { EmpresaUpdate, ContactoInsert } from '../../core/types/entities'

type Tab = 'resumen' | 'contactos' | 'contratos' | 'actividades' | 'propuestas'

export default function EmpresaDetailPage() {
  const { id } = useParams<{ id: string }>()
  const { data: empresa, isLoading } = useEmpresaById(id)
  const updateMut = useUpdateEmpresa()
  const deleteMut = useDeleteEmpresa()
  const [editing, setEditing] = useState(false)
  const [tab, setTab] = useState<Tab>('resumen')
  const [confirmDelete, setConfirmDelete] = useState(false)

  if (isLoading) return <div className="p-8 text-slate-500">Cargando…</div>
  if (!empresa) return <div className="p-8 text-slate-500">Empresa no encontrada</div>

  const onSave = async (values: EmpresaUpdate) => {
    await updateMut.mutateAsync({ id: empresa.id, patch: values })
    setEditing(false)
  }

  const onDeleteConfirmed = async () => {
    await deleteMut.mutateAsync(empresa.id)
    setConfirmDelete(false)
    window.location.href = '/empresas'
  }

  return (
    <div className="p-8">
      <Link to="/empresas" className="mb-4 inline-flex items-center gap-2 text-sm text-slate-600 hover:text-slate-900">
        <ArrowLeft className="h-4 w-4" /> Empresas
      </Link>

      <div className="mb-6 flex items-start justify-between">
        <div>
          <h1 className="text-2xl font-bold text-slate-900">{empresa.nombre}</h1>
          <p className="text-sm text-slate-500">
            {empresa.nif ?? 'Sin NIF'} · {empresa.tipo ?? 'Sin tipo'}
          </p>
        </div>
        <div className="flex gap-2">
          <button type="button" onClick={() => setEditing(!editing)} className="inline-flex items-center gap-2 rounded-md border border-slate-300 px-3 py-1.5 text-sm hover:bg-slate-50">
            <Pencil className="h-3.5 w-3.5" /> {editing ? 'Cancelar' : 'Editar'}
          </button>
          <button type="button" onClick={() => setConfirmDelete(true)} className="inline-flex items-center gap-2 rounded-md border border-red-200 px-3 py-1.5 text-sm text-red-700 hover:bg-red-50">
            <Trash2 className="h-3.5 w-3.5" /> Eliminar
          </button>
        </div>
      </div>

      <div className="grid gap-6 lg:grid-cols-[2fr_1fr]">
        <div>
          {editing ? (
            <div className="rounded-lg border border-slate-200 bg-white p-6 shadow-sm">
              <EmpresaForm
                defaultValues={empresa}
                onSubmit={onSave}
                onCancel={() => setEditing(false)}
                submitting={updateMut.isPending}
              />
            </div>
          ) : (
            <>
              <TabsNav tab={tab} setTab={setTab} />
              <div className="rounded-lg border border-slate-200 bg-white p-6 shadow-sm">
                {tab === 'resumen' && <Resumen empresa={empresa} />}
                {tab === 'actividades' && (
                  <div className="space-y-4">
                    <ActividadTimeline entidadTipo="empresa" entidadId={empresa.id} />
                    <Link
                      to={`/actividades?entidad_tipo=empresa&entidad_id=${empresa.id}`}
                      className="inline-flex items-center gap-1 text-xs text-slate-600 hover:text-slate-900"
                    >
                      Ver todas las actividades de esta empresa →
                    </Link>
                  </div>
                )}
                {tab === 'contactos' && <ContactosSection empresaId={empresa.id} />}
                {(tab === 'contratos' || tab === 'propuestas') && (
                  <p className="text-sm text-slate-500">
                    Sección "{tab}" — próximas iteraciones.
                  </p>
                )}
              </div>
            </>
          )}
        </div>

        <aside className="space-y-4">
          <InfoCard title="Datos rápidos">
            <InfoRow label="Email" value={empresa.email_principal ?? '—'} />
            <InfoRow label="Teléfono" value={empresa.telefono_principal ?? '—'} />
            <InfoRow label="Web" value={empresa.web ?? '—'} />
            <InfoRow label="Segmento" value={empresa.segmento ?? '—'} />
            <InfoRow label="Creada" value={formatDate(empresa.created_at, 'long')} />
          </InfoCard>
        </aside>
      </div>

      <ConfirmDialog
        isOpen={confirmDelete}
        title="Eliminar empresa"
        message={`¿Seguro que quieres eliminar "${empresa.nombre}"? (soft delete)`}
        confirmLabel="Eliminar"
        variant="danger"
        submitting={deleteMut.isPending}
        onConfirm={onDeleteConfirmed}
        onCancel={() => setConfirmDelete(false)}
      />
    </div>
  )
}

function TabsNav({ tab, setTab }: { tab: Tab; setTab: (t: Tab) => void }) {
  const tabs: Tab[] = ['resumen', 'contactos', 'contratos', 'actividades', 'propuestas']
  return (
    <div className="mb-4 flex gap-1 border-b border-slate-200">
      {tabs.map((t) => (
        <button
          key={t}
          type="button"
          onClick={() => setTab(t)}
          className={`px-4 py-2 text-sm capitalize ${
            tab === t ? 'border-b-2 border-slate-900 font-medium text-slate-900' : 'text-slate-500 hover:text-slate-700'
          }`}
        >
          {t}
        </button>
      ))}
    </div>
  )
}

function Resumen({ empresa }: { empresa: NonNullable<ReturnType<typeof useEmpresaById>['data']> }) {
  return (
    <dl className="grid grid-cols-2 gap-4 text-sm">
      <InfoRow label="Dirección" value={empresa.direccion ?? '—'} />
      <InfoRow label="CP / Ciudad" value={`${empresa.cp ?? '—'} · ${empresa.ciudad ?? '—'}`} />
      <InfoRow label="Provincia" value={empresa.provincia ?? '—'} />
      <InfoRow label="País" value={empresa.pais ?? 'ES'} />
      <InfoRow label="Tags" value={empresa.tags?.join(', ') || '—'} />
      <InfoRow label="Notas" value={empresa.notas ?? '—'} />
    </dl>
  )
}

function InfoCard({ title, children }: { title: string; children: React.ReactNode }) {
  return (
    <div className="rounded-lg border border-slate-200 bg-white p-4 shadow-sm">
      <h3 className="mb-3 text-sm font-semibold text-slate-900">{title}</h3>
      <dl className="space-y-2 text-sm">{children}</dl>
    </div>
  )
}

function InfoRow({ label, value }: { label: string; value: string }) {
  return (
    <div>
      <dt className="text-xs uppercase tracking-wide text-slate-500">{label}</dt>
      <dd className="text-slate-900">{value}</dd>
    </div>
  )
}

function ContactosSection({ empresaId }: { empresaId: string }) {
  const contactos = useContactosPorEmpresa(empresaId)
  const createMut = useCreateContacto()
  const [adding, setAdding] = useState(false)

  const onSubmit = async (values: ContactoInsert) => {
    await createMut.mutateAsync({ ...values, empresa_id: empresaId })
    setAdding(false)
  }

  const lista = contactos.data ?? []

  return (
    <div>
      <div className="mb-4 flex items-center justify-between">
        <h3 className="text-sm font-semibold text-slate-900">Contactos de la empresa</h3>
        {lista.length > 0 && (
          <button
            type="button"
            onClick={() => setAdding(true)}
            className="inline-flex items-center gap-1.5 rounded-md bg-slate-900 px-3 py-1.5 text-xs text-white hover:bg-slate-800"
          >
            <Plus className="h-3.5 w-3.5" /> Añadir contacto
          </button>
        )}
      </div>

      {contactos.isLoading && <p className="text-sm text-slate-500">Cargando…</p>}

      {!contactos.isLoading && lista.length === 0 && (
        <div className="rounded-md border border-dashed border-slate-300 p-6 text-center">
          <p className="mb-3 text-sm text-slate-500">Sin contactos registrados</p>
          <button
            type="button"
            onClick={() => setAdding(true)}
            className="inline-flex items-center gap-1.5 rounded-md bg-slate-900 px-3 py-1.5 text-xs text-white hover:bg-slate-800"
          >
            <Plus className="h-3.5 w-3.5" /> Añadir el primero
          </button>
        </div>
      )}

      {lista.length > 0 && (
        <ul className="divide-y divide-slate-100">
          {lista.map((c) => {
            const phones = [c.telefono, c.movil].filter(Boolean).join(' · ')
            return (
              <li key={c.id} className="py-3">
                <div className="flex items-start justify-between gap-3">
                  <div className="min-w-0 flex-1">
                    <p className="font-medium text-slate-900">
                      {c.nombre}{c.apellidos ? ` ${c.apellidos}` : ''}
                    </p>
                    {c.cargo && <p className="text-xs text-slate-500">{c.cargo}</p>}
                    {(c.email || phones) && (
                      <p className="mt-1 text-xs text-slate-600">
                        {c.email ?? ''}{c.email && phones ? ' · ' : ''}{phones}
                      </p>
                    )}
                  </div>
                  <div className="flex shrink-0 gap-1">
                    {c.es_decisor && (
                      <span className="rounded-full bg-amber-100 px-2 py-0.5 text-[10px] font-medium text-amber-800">Decisor</span>
                    )}
                    {c.es_firmante && (
                      <span className="rounded-full bg-blue-100 px-2 py-0.5 text-[10px] font-medium text-blue-800">Firmante</span>
                    )}
                  </div>
                </div>
              </li>
            )
          })}
        </ul>
      )}

      {adding && (
        <>
          <div className="fixed inset-0 z-40 bg-black/30" onClick={() => setAdding(false)} />
          <div className="fixed right-0 top-0 z-50 h-full w-full max-w-xl overflow-y-auto bg-white shadow-xl">
            <div className="flex items-center justify-between border-b border-slate-200 p-4">
              <h2 className="text-lg font-semibold text-slate-900">Nuevo contacto</h2>
              <button type="button" onClick={() => setAdding(false)} aria-label="Cerrar" className="rounded p-1 text-slate-500 hover:bg-slate-100">
                <X className="h-5 w-5" />
              </button>
            </div>
            <div className="p-6">
              <ContactoForm
                defaultValues={{ empresa_id: empresaId }}
                onSubmit={onSubmit}
                onCancel={() => setAdding(false)}
                submitting={createMut.isPending}
              />
            </div>
          </div>
        </>
      )}
    </div>
  )
}

